    13→import { useAuth } from '../../context/AuthContext';
    14→import api from '../../services/api';
    15→import { useTheme } from '../../context/ThemeContext';
    16→
    17→const DAYS = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
    18→
    19→export default function TimetableScreen() {
    20→  const { user } = useAuth();
    21→  const { colors } = useTheme();
    22→  const [timetable, setTimetable] = useState<any>(null);
    23→  const [loading, setLoading] = useState(true);
    24→  const [refreshing, setRefreshing] = useState(false);
    25→
    26→  const loadTimetable = useCallback(async () => {
    27→    if (!user?.id) return;
    28→    try {
    29→      const data = await api.getTimetable(user.id);
    30→      setTimetable(data);
    31→    } catch (error) {
    32→      console.error('Error loading timetable:', error);
    33→      Alert.alert('Error', 'Failed to load timetable. Please try again.');
    34→    } finally {
    35→      setLoading(false);
    36→      setRefreshing(false);
    37→    }
    38→  }, [user?.id]);
    39→
    40→  useEffect(() => {
    41→    loadTimetable();
    42→  }, [loadTimetable]);
    43→
    44→  const onRefresh = useCallback(() => {
    45→    setRefreshing(true);
    46→    loadTimetable();
    47→  }, [loadTimetable]);
    48→
    49→  if (loading) {
    50→    return (
    51→      <SafeAreaView style={[styles.centerContainer, { backgroundColor: colors.backgroundGray }]}>
    52→        <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
    53→        <ActivityIndicator size="large" color={colors.primary} />
    54→      </SafeAreaView>
    55→    );
    56→  }
    57→
    58→  return (
    59→    <SafeAreaView style={[styles.container, { backgroundColor: colors.backgroundGray }]}>
    60→      <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />
    61→      <ScrollView
    62→        refreshControl={
    63→          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} colors={[colors.primary]} tintColor={colors.primary} />
    64→        }
    65→      >
    66→        {DAYS.map((day) => {
