// Message bubble component
const MessageBubble: React.FC<{
  message: Message;
  isOwn: boolean;
  onLongPress: (message: Message) => void;
  colors: any;
}> = ({ message, isOwn, onLongPress, colors }) => {
  const getStatusIcon = () => {
    switch (message.status) {
      case 'sending':
        return <Ionicons name="time-outline" size={12} color={isOwn ? 'rgba(255,255,255,0.7)' : colors.textSecondary} />;
      case 'sent':
        return <Ionicons name="checkmark" size={12} color={isOwn ? 'rgba(255,255,255,0.7)' : colors.textSecondary} />;
      case 'delivered':
        return <Ionicons name="checkmark-done" size={12} color={isOwn ? 'rgba(255,255,255,0.7)' : colors.textSecondary} />;
      case 'read':
        return <Ionicons name="checkmark-done" size={12} color={colors.primary} />;
      default:
        return null;
    }
  };

  // Render reply indicator
  const renderReplyIndicator = () => {
    if (!message.replyTo) return null;

    return (
      <View style={[styles.replyIndicator, { backgroundColor: isOwn ? 'rgba(255,255,255,0.15)' : colors.primary + '15' }]}>
        <View style={[styles.replyBar, { backgroundColor: colors.primary }]} />
        <View style={styles.replyContent}>
          <Text style={[styles.replySender, { color: colors.primary }]} numberOfLines={1}>
            {message.replyTo.senderName || 'Unknown'}
          </Text>
          <Text style={[styles.replyText, { color: isOwn ? 'rgba(255,255,255,0.7)' : colors.textSecondary }]} numberOfLines={1}>
            {message.replyTo.content || (message.replyTo.type === 'image' ? '📷 Image' : '📎 File')}
          </Text>
        </View>
      </View>
    );
  };

  // Render forward indicator
  const renderForwardIndicator = () => {
    if (!message.forwardedFrom) return null;

    return (
      <View style={styles.forwardIndicator}>
        <Ionicons name="arrow-forward" size={12} color={isOwn ? 'rgba(255,255,255,0.6)' : colors.textSecondary} />
        <Text style={[styles.forwardText, { color: isOwn ? 'rgba(255,255,255,0.6)' : colors.textSecondary }]}>
          Forwarded from {message.forwardedFrom.originalSenderName}
        </Text>
      </View>
    );
  };

  // Render reactions
  const renderReactions = () => {
    if (!message.reactions || message.reactions.length === 0) return null;

    // Group reactions by emoji
    const groupedReactions = message.reactions.reduce((acc, reaction) => {
      if (!acc[reaction.emoji]) {
        acc[reaction.emoji] = { count: 0, users: [] };
      }
      acc[reaction.emoji].count++;
      acc[reaction.emoji].users.push(reaction.userId);
      return acc;
    }, {} as Record<string, { count: number; users: string[] }>);

    return (
      <View style={[styles.reactionsContainer, isOwn ? styles.reactionsContainerOwn : styles.reactionsContainerOther]}>
        {Object.entries(groupedReactions).map(([emoji, data]) => (
          <View
            key={emoji}
            style={[
              styles.reactionBadge,
              { backgroundColor: isOwn ? 'rgba(255,255,255,0.2)' : colors.primary + '15' }
            ]}
          >
            <Text style={styles.reactionEmoji}>{emoji}</Text>
            {data.count > 1 && (
              <Text style={[styles.reactionCount, { color: isOwn ? '#fff' : colors.text }]}>
                {data.count}
              </Text>
            )}
          </View>
        ))}
      </View>
    );
  };

  const renderMessageContent = () => {
    // If it's an image, display the image
    if (message.type === 'image' && message.fileUrl) {
      return (
        <>
          <View style={styles.imageContainer}>
            <Image
              source={{ uri: message.fileUrl }}
              style={[styles.messageImage, { backgroundColor: colors.border }]}
              resizeMode="cover"
            />
            {/* Show loading spinner overlay while uploading */}
            {message.status === 'sending' && (
              <View style={styles.imageLoadingOverlay}>
                <ActivityIndicator size="small" color={isOwn ? '#fff' : colors.primary} />
                <Text style={[styles.loadingText, isOwn ? { color: '#fff' } : { color: colors.text }]}>
                  Uploading...
                </Text>
              </View>
            )}
          </View>
          {message.fileName && (
            <Text style={[styles.messageContent, isOwn && styles.ownMessageText, styles.imageCaption, isOwn ? { color: 'rgba(255,255,255,0.8)' } : { color: colors.text }]}>
              {message.fileName}
            </Text>
          )}
        </>
      );
    }

    // If it's a file, show file info
    if (message.type === 'file') {
      return (
        <View style={styles.fileContainer}>
          <Ionicons name="document" size={32} color={isOwn ? colors.white : colors.primary} />
          <View style={styles.fileInfo}>
            <Text style={[styles.messageContent, isOwn ? styles.ownMessageText : { color: colors.text }]} numberOfLines={1}>
              {message.fileName || 'Document'}
            </Text>
            {message.fileSize && (
              <Text style={[styles.messageTime, isOwn ? styles.ownMessageText : { color: colors.textSecondary }]}>
                {(message.fileSize / 1024).toFixed(2)} KB
              </Text>
            )}
          </View>
        </View>
      );
    }

    // Default: show text content
    return (
      <Text style={[styles.messageContent, isOwn ? styles.ownMessageText : { color: colors.text }]}>
        {message.content}
        {message.isEdited && (
          <Text style={[styles.editedText, { color: isOwn ? 'rgba(255,255,255,0.5)' : colors.textSecondary }]}> edited</Text>
        )}
      </Text>
    );
  };

  return (
    <View style={styles.messageBubbleWrapper}>
      {message.pinned && (
        <View style={[styles.pinnedIndicator, { backgroundColor: colors.primary + '15' }]}>
          <Ionicons name="pin" size={12} color={colors.primary} />
          <Text style={[styles.pinnedText, { color: colors.primary }]}>Pinned</Text>
        </View>
      )}
      <TouchableOpacity
        activeOpacity={0.95}
        onPress={() => console.log('👆 [BUBBLE] Short press:', message.id)}
        onLongPress={() => {
          console.log('🎯 [BUBBLE] Long press triggered for message:', message.id);
          onLongPress(message);
        }}
        delayLongPress={500}
        hitSlop={{ top: 10, bottom: 10, left: 10, right: 10 }}
      >
        <View
          style={[
            styles.messageBubble,
            isOwn ? styles.ownMessageBubble : styles.otherMessageBubble,
            message.type === 'image' && styles.imageMessageBubble,
            isOwn ? { backgroundColor: colors.primary } : { backgroundColor: colors.inputBackground },
          ]}
        >
          {renderForwardIndicator()}
          {renderReplyIndicator()}
          {!isOwn && (
            <Text style={[styles.senderName, { color: colors.primary }]}>{message.senderName}</Text>
          )}
          {renderMessageContent()}
          <View style={styles.messageMeta}>
            <Text style={[styles.messageTime, { color: isOwn ? 'rgba(255,255,255,0.7)' : colors.textSecondary }, isOwn && styles.ownMessageTime]}>
              {format(new Date(message.createdAt), 'HH:mm')}
            </Text>
            {isOwn && (
              <View style={styles.statusIcon}>
                {getStatusIcon()}
              </View>
            )}
          </View>
        </View>
      </TouchableOpacity>
      {renderReactions()}
    </View>
  );
};

// Conversation item
const ConversationItem: React.FC<{
  conversation: Conversation;
  onPress: () => void;
  colors: any;
}> = ({ conversation, onPress, colors }) => {
  const getInitials = (name: string) => {
    return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
  };

  const formatTime = (date: Date) => {
    if (isToday(date)) return format(date, 'HH:mm');
    if (isYesterday(date)) return 'Yesterday';
    return format(date, 'dd/MM');
  };

  const displayName = conversation.type === 'group'
    ? conversation.groupName || 'Group'
    : conversation.otherParticipant?.name || 'Unknown';

  return (
    <TouchableOpacity
      style={[styles.conversationItem, { backgroundColor: colors.card }]}
      onPress={onPress}
      activeOpacity={0.7}
    >
      <View style={styles.avatarContainer}>
        <View style={[styles.avatar, conversation.type === 'group' && styles.groupAvatar, { backgroundColor: colors.primary + '15' }]}>
          <Text style={[styles.avatarText, { color: colors.primary }]}>{getInitials(displayName)}</Text>
        </View>
        {conversation.otherParticipant?.online && <View style={[styles.onlineIndicator, { backgroundColor: colors.success, borderColor: colors.card }]} />}
      </View>
      <View style={styles.conversationInfo}>
        <View style={styles.conversationHeader}>
          <Text style={[styles.conversationName, { color: colors.text }]} numberOfLines={1}>
            {displayName}
          </Text>
          {conversation.lastMessage?.timestamp && (
            <Text style={[
              styles.time,
              conversation.unreadCount ? styles.unreadTime : null,
              { color: conversation.unreadCount ? colors.primary : colors.textSecondary }
            ]}>
              {formatTime(conversation.lastMessage.timestamp)}
            </Text>
          )}
        </View>
        <View style={styles.conversationFooter}>
          <Text style={[
            styles.lastMessage,
            conversation.unreadCount ? styles.unreadMessage : null,
            { color: conversation.unreadCount ? colors.text : colors.textSecondary }
          ]} numberOfLines={1}>
            {conversation.lastMessage?.content || 'No messages yet'}
          </Text>
          {conversation.unreadCount ? (
            <View style={[styles.unreadBadge, { backgroundColor: colors.primary }]}>
              <Text style={[styles.unreadBadgeText, { color: colors.white }]}>{conversation.unreadCount}</Text>
            </View>
          ) : null}
        </View>
      </View>
    </TouchableOpacity>
  );
};

// Floating action button
const FloatingButton: React.FC<{ onPress: () => void; colors: any }> = ({ onPress, colors }) => {
  return (
    <TouchableOpacity
      style={[styles.floatingButton, { backgroundColor: colors.primary }]}
      onPress={onPress}
      activeOpacity={0.8}
    >
      <Ionicons name="add" size={28} color={colors.white} />
    </TouchableOpacity>
  );
};

export default function MessagesScreen() {
  const { user } = useAuth();
  const router = useRouter();
  const { colors, activeTheme } = useTheme();
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [selectedConversation, setSelectedConversation] = useState<Conversation | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const [searchQuery, setSearchQuery] = useState('');
  const [showNewChatModal, setShowNewChatModal] = useState(false);
  const [contactsSearchQuery, setContactsSearchQuery] = useState('');
  const [availableContacts, setAvailableContacts] = useState<{
    staff: Array<{ id: string; name: string; role?: string; avatar?: string }>;
    students: Array<{ id: string; name: string; rollNo?: number; avatar?: string }>;
  }>({ staff: [], students: [] });
  const [loadingContacts, setLoadingContacts] = useState(false);

  // File upload states
  const [showAttachmentModal, setShowAttachmentModal] = useState(false);
  const [selectedFile, setSelectedFile] = useState<{ uri: string; name: string; type: string; size?: number } | null>(null);
  const [uploadingFile, setUploadingFile] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);

  // Message actions state
  const [showMessageActions, setShowMessageActions] = useState(false);
  const [selectedMessageForAction, setSelectedMessageForAction] = useState<Message | null>(null);
  const [replyingTo, setReplyingTo] = useState<Message | null>(null);
  const [editingMessage, setEditingMessage] = useState<Message | null>(null);
  const [editText, setEditText] = useState('');
  const [showEmojiPicker, setShowEmojiPicker] = useState(false);
  const [forwardingMessage, setForwardingMessage] = useState<Message | null>(null);
  const [showForwardModal, setShowForwardModal] = useState(false);

  const scrollViewRef = useRef<ScrollView>(null);
  const inputRef = useRef<TextInput>(null);
  const typingTimeoutRef = useRef<NodeJS.Timeout>();
  const selectedConversationRef = useRef<Conversation | null>(null);

  // Keep ref in sync with state
  useEffect(() => {
    selectedConversationRef.current = selectedConversation;
  }, [selectedConversation]);

  // Load conversations on mount
  useEffect(() => {
    if (user?.id) {
      loadConversations();
      setupSocketListeners();
    }

    return () => {
      // Cleanup socket listeners
      if (socketService.isConnected()) {
        socketService.off('new_message', handleNewMessage);
        socketService.off('user_typing', handleUserTyping);
        socketService.off('user_status', handleUserStatus);
        socketService.off('message_read', handleMessageRead);
      }
    };
  }, [user?.id]);

  // Load contacts when modal opens
  useEffect(() => {
    if (showNewChatModal || showForwardModal) {
      loadContacts();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [showNewChatModal, showForwardModal]);

  // Setup socket listeners
  const setupSocketListeners = () => {
    console.log('🔧 [CHAT] Setting up socket listeners...');
    socketService.on('new_message', handleNewMessage);
    socketService.on('user_typing', handleUserTyping);
    socketService.on('user_status', handleUserStatus);
    socketService.on('message_read', handleMessageRead);
    console.log('✅ [CHAT] Socket listeners registered');
  };

  // Handle new message from socket
  const handleNewMessage = (data: { message: Message }) => {
    const { message } = data;

    console.log('📱 [CHAT] handleNewMessage called:', {
      messageId: message.id,
      conversationId: message.conversationId,
      type: message.type,
      senderId: message.senderId,
      currentConversationId: selectedConversationRef.current?.id,
      willAddToState: String(message.conversationId) === String(selectedConversationRef.current?.id),
    });

    // Use ref to get current conversation (avoids stale closure)
    const currentConversation = selectedConversationRef.current;

    // If this message is for the current conversation, add it
    if (currentConversation && String(message.conversationId) === String(currentConversation.id)) {
      console.log('✅ [CHAT] Processing message for current conversation');

      setMessages(prev => {
        // Check if this is a message we sent optimistically (replace temp message)
        const tempMessageIndex = prev.findIndex(m =>
          m.id.startsWith('temp-') &&
          String(m.senderId) === String(message.senderId) &&
          m.type === message.type &&
          Math.abs(new Date(m.createdAt).getTime() - new Date(message.createdAt).getTime()) < 5000 // Within 5 seconds
        );

        if (tempMessageIndex !== -1) {
          console.log('🔄 [CHAT] Replacing temporary message with real one');
          const newMessages = [...prev];
          newMessages[tempMessageIndex] = message;
          return newMessages;
        }

        // Check if message already exists (avoid duplicates)
        if (prev.some(m => m.id === message.id)) {
          console.log('⚠️ [CHAT] Message already exists, skipping');
          return prev;
        }

        // Add new message
        console.log('➕ [CHAT] Adding new message to state');
        const newMessages = [...prev, message];
        console.log('📝 [CHAT] Messages count:', newMessages.length);
        return newMessages;
      });

      setTimeout(() => {
        scrollViewRef.current?.scrollToEnd({ animated: true });
      }, 100);

      // Mark as read
      socketService.markAsRead(message.id, message.conversationId);
    } else {
      console.log('⚠️ [CHAT] Message not for current conversation, skipping');
    }

    // Reload conversations to update last message
    loadConversations();
  };

  // Handle user typing indicator
  const handleUserTyping = (data: TypingIndicatorType) => {
    const currentConversation = selectedConversationRef.current;
    if (data.conversationId === currentConversation?.id) {
      if (data.isTyping) {
        setTypingUsers(prev => new Set([...prev, data.userId]));
      } else {
        setTypingUsers(prev => {
          const newSet = new Set(prev);
          newSet.delete(data.userId);
          return newSet;
        });
      }
    }
  };

  // Handle user status change
  const handleUserStatus = (data: { userId: string; status: string; lastSeen?: Date }) => {
    setConversations(prev => prev.map(conv => {
      if (conv.otherParticipant?.userId === data.userId) {
        return {
          ...conv,
          otherParticipant: {
            ...conv.otherParticipant!,
            online: data.status === 'online',
            lastSeen: data.lastSeen,
          },
        };
      }
      return conv;
    }));

    if (selectedConversation?.otherParticipant?.userId === data.userId) {
      setSelectedConversation(prev => prev ? {
        ...prev,
        otherParticipant: {
          ...prev.otherParticipant!,
          online: data.status === 'online',
          lastSeen: data.lastSeen,
        },
      } : null);
    }
  };

  // Handle message read receipt
  const handleMessageRead = (data: { messageId: string; conversationId: string; readAt: Date }) => {
    const currentConversation = selectedConversationRef.current;
    if (currentConversation && data.conversationId === currentConversation.id) {
      setMessages(prev => prev.map(msg =>
        msg.id === data.messageId ? { ...msg, status: 'read', readAt: data.readAt } : msg
      ));
    }
  };

  // Load conversations
  const loadConversations = async () => {
    if (!user?.id) return;

    try {
      setLoading(true);
      const data = await chatService.getConversations(user.id, 'staff');
      setConversations(data);
    } catch (error) {
      console.error('Error loading conversations:', error);
      Alert.alert('Error', 'Failed to load conversations');
    } finally {
      setLoading(false);
    }
  };

  // Load available contacts
  const loadContacts = async () => {
    try {
      setLoadingContacts(true);
      const data = await chatService.getContacts('staff');
      setAvailableContacts(data);
    } catch (error) {
      console.error('Error loading contacts:', error);
      Alert.alert('Error', 'Failed to load contacts');
    } finally {
      setLoadingContacts(false);
    }
  };

  // Start new conversation with selected contact
  const startConversation = async (contactId: string, contactUserType: 'staff' | 'student') => {
    if (!user?.id) return;

    try {
      // Create or get conversation
      const conversation = await chatService.createConversation(
        user.id,
        'staff',
        contactId,
        contactUserType
      );

      // Add to conversations list
      setConversations(prev => [conversation, ...prev]);

      // Load the conversation
      loadMessages(conversation);

      // Close modal
      setShowNewChatModal(false);
      setContactsSearchQuery('');
    } catch (error: any) {
      console.error('Error starting conversation:', error);
      Alert.alert('Error', error.message || 'Failed to start conversation');
    }
  };

  // Load messages for selected conversation
  const loadMessages = async (conversation: Conversation) => {
    setSelectedConversation(conversation);

    try {
      const data = await chatService.getMessages(conversation.id);
      setMessages(data);

      // Join conversation room
      socketService.joinConversation(conversation.id);

      // Mark messages as read
      socketService.markAsRead(null, conversation.id);

      // Scroll to bottom
      setTimeout(() => {
        scrollViewRef.current?.scrollToEnd({ animated: true });
      }, 100);
    } catch (error) {
      console.error('Error loading messages:', error);
      Alert.alert('Error', 'Failed to load messages');
    }
  };

  // Send message
  const sendMessage = async () => {
    if (!newMessage.trim() || !selectedConversation || !user || sending) return;

    const messageContent = newMessage.trim();
    setNewMessage('');
    setSending(true);

    // Store reply info and clear reply state
    const currentReplyTo = replyingTo;
    if (currentReplyTo) {
      setReplyingTo(null);
    }

    // Create temporary message object for optimistic UI
    const tempMessage: Message = {
      id: `temp-${Date.now()}`,
      conversationId: selectedConversation.id,
      senderId: user.id,
      senderName: user.name,
      receiverId: selectedConversation.otherParticipant.userId,
      receiverName: selectedConversation.otherParticipant.name,
      content: messageContent,
      type: 'text',
      status: 'sending',
      createdAt: new Date(),
      replyTo: currentReplyTo ? {
        messageId: currentReplyTo.id,
        content: currentReplyTo.content,
        senderId: currentReplyTo.senderId,
        senderName: currentReplyTo.senderName,
      } : null,
    };

    // Add message to state immediately (optimistic update)
    setMessages(prev => [...prev, tempMessage]);
    console.log('✅ [CHAT] Added text message optimistically to state');

    // Scroll to bottom
    setTimeout(() => {
      scrollViewRef.current?.scrollToEnd({ animated: true });
    }, 100);

    try {
      // Send via socket
      if (selectedConversation.otherParticipant) {
        socketService.sendMessage({
          conversationId: selectedConversation.id,
          receiverId: selectedConversation.otherParticipant.userId,
          receiverModel: selectedConversation.otherParticipant.userType === 'staff' ? 'Staff' : 'Student',
          content: messageContent,
          type: 'text',
          replyTo: currentReplyTo ? {
            messageId: currentReplyTo.id,
            content: currentReplyTo.content,
            senderId: currentReplyTo.senderId,
            senderName: currentReplyTo.senderName,
          } : undefined,
        });
      }

      // Stop typing indicator
      socketService.sendTyping(selectedConversation.id, false);
    } catch (error) {
      console.error('Error sending message:', error);
      Alert.alert('Error', 'Failed to send message');
      setNewMessage(messageContent); // Restore message on error
      // Remove the optimistic message on error
      setMessages(prev => prev.filter(msg => msg.id !== tempMessage.id));
    } finally {
      setSending(false);
    }
  };

  // Handle typing
  const handleTyping = (text: string) => {
    setNewMessage(text);

    if (!selectedConversation) return;

    // Send typing indicator
    socketService.sendTyping(selectedConversation.id, true);

    // Clear previous timeout
    if (typingTimeoutRef.current) {
      clearTimeout(typingTimeoutRef.current);
    }

    // Stop typing after 2 seconds of inactivity
    typingTimeoutRef.current = setTimeout(() => {
      socketService.sendTyping(selectedConversation.id, false);
    }, 2000);
  };

  // Request permissions and pick image
  const requestPermissionsAndPickImage = async (useCamera: boolean = false) => {
    try {
      if (useCamera) {
        // Request camera permissions
        const { status } = await ImagePicker.requestCameraPermissionsAsync();
        if (status !== 'granted') {
          Alert.alert('Permission needed', 'Camera permission is required to take photos');
          return;
        }

        const result = await ImagePicker.launchCameraAsync({
          mediaTypes: ImagePicker.MediaTypeOptions.Images,
          quality: 0.8,
          allowsEditing: true,
        });

        if (!result.canceled && result.assets[0]) {
          const asset = result.assets[0];
          setSelectedFile({
            uri: asset.uri,
            name: `photo_${Date.now()}.jpg`,
            type: asset.mimeType || 'image/jpeg',
            size: asset.fileSize,
          });
          setShowAttachmentModal(false);
        }
      } else {
        // Request library permissions
        const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();
        if (status !== 'granted') {
          Alert.alert('Permission needed', 'Gallery permission is required to select photos');
          return;
        }

        const result = await ImagePicker.launchImageLibraryAsync({
          mediaTypes: ImagePicker.MediaTypeOptions.Images,
          quality: 0.8,
          allowsEditing: true,
        });

        if (!result.canceled && result.assets[0]) {
          const asset = result.assets[0];
          setSelectedFile({
            uri: asset.uri,
            name: asset.fileName || `photo_${Date.now()}.jpg`,
            type: asset.mimeType || 'image/jpeg',
            size: asset.fileSize,
          });
          setShowAttachmentModal(false);
        }
      }
    } catch (error) {
      console.error('Error picking image:', error);
      Alert.alert('Error', 'Failed to select image');
    }
  };

  // Upload and send file
  const handleFileUpload = async () => {
    if (!selectedFile || !selectedConversation || !user) return;

    setUploadingFile(true);
    setUploadProgress(0);

    // WhatsApp-style: Add message immediately with local URI and "sending" status
    const tempMessageId = `temp-${Date.now()}`;
    const isImage = selectedFile.type.startsWith('image/');

    const tempMessage: Message = {
      id: tempMessageId,
      conversationId: selectedConversation.id,
      senderId: user.id,
      senderName: user.name,
      receiverId: selectedConversation.otherParticipant.userId,
      receiverName: selectedConversation.otherParticipant.name,
      content: isImage ? '📷 Image' : selectedFile.name,
      type: isImage ? 'image' : 'file',
      fileUrl: selectedFile.uri, // Start with local URI
      fileName: selectedFile.name,
      fileSize: selectedFile.size,
      status: 'sending',
      createdAt: new Date(),
    };

    // Add message to state immediately (optimistic update)
    setMessages(prev => [...prev, tempMessage]);
    console.log('✅ [CHAT] Added file message optimistically to state with local URI');

    // Scroll to bottom
    setTimeout(() => {
      scrollViewRef.current?.scrollToEnd({ animated: true });
    }, 100);

    // Clear file selection immediately
    setSelectedFile(null);

    try {
      // Upload file in background
      console.log('📤 [CHAT] Starting file upload...');
      const uploadData = await chatService.uploadFile(selectedFile);
      console.log('✅ [CHAT] File uploaded successfully:', uploadData.url);

      // Update message with server URL and change status to 'sent'
      setMessages(prev => prev.map(msg => {
        if (msg.id === tempMessageId) {
          return {
            ...msg,
            fileUrl: uploadData.url,
            status: 'sent',
          };
        }
        return msg;
      }));

      // Send message via socket with server URL
      socketService.sendMessage({
        conversationId: selectedConversation.id,
        receiverId: selectedConversation.otherParticipant.userId,
        receiverModel: selectedConversation.otherParticipant.userType === 'staff' ? 'Staff' : 'Student',
        content: isImage ? '📷 Image' : selectedFile.name,
        type: isImage ? 'image' : 'file',
        fileUrl: uploadData.url,
        fileName: selectedFile.name,
        fileSize: selectedFile.size || undefined,
      });

      console.log('✅ [CHAT] File message sent via socket');
    } catch (error: any) {
      console.error('❌ [CHAT] File upload failed:', error);

      // Update message status to show error
      setMessages(prev => prev.map(msg => {
        if (msg.id === tempMessageId) {
          return {
            ...msg,
            status: 'sending', // Keep showing to indicate it needs retry
            content: '❌ Failed to send. Tap to retry.',
          };
        }
        return msg;
      }));

      Alert.alert(
        'Upload Failed',
        'Failed to upload file. Please try again.',
        [
          {
            text: 'Retry',
            onPress: () => {
              // Restore file selection and retry
              setSelectedFile(selectedFile);
              setUploadingFile(false);
            }
          },
          {
            text: 'Cancel',
            style: 'cancel',
            onPress: () => {
              // Remove failed message
              setMessages(prev => prev.filter(msg => msg.id !== tempMessageId));
            }
          }
        ]
      );
    } finally {
      setUploadingFile(false);
      setUploadProgress(0);
    }
  };

  // Cancel file selection
  const cancelFileUpload = () => {
    setSelectedFile(null);
  };

  // Message action handlers
  const handleMessageLongPress = (message: Message) => {
    console.log('🎯 [CHAT] Long press detected:', message.id, message.type);
    setSelectedMessageForAction(message);
    setShowMessageActions(true);
  };

  const handleMessageAction = async (action: string) => {
    if (!selectedMessageForAction) return;

    const message = selectedMessageForAction;

    switch (action) {
      case 'reply':
        setReplyingTo(message);
        inputRef.current?.focus();
        break;

      case 'copy':
        if (message.content) {
          await Clipboard.setStringAsync(message.content);
          Alert.alert('Copied', 'Text copied to clipboard');
        }
        break;

      case 'delete':
        Alert.alert(
          'Delete Message',
          'Are you sure you want to delete this message?',
          [
            { text: 'Cancel', style: 'cancel' },
            {
              text: 'Delete',
              style: 'destructive',
              onPress: async () => {
                try {
                  await chatService.deleteMessage(message.id, message.conversationId);
                  setMessages(prev => prev.filter(m => m.id !== message.id));
                  Alert.alert('Success', 'Message deleted');
                } catch (error) {
                  Alert.alert('Error', 'Failed to delete message');
                }
              }
            }
          ]
        );
        break;

      case 'forward':
        setForwardingMessage(message);
        setShowForwardModal(true);
        setShowMessageActions(false);
        break;

      case 'pin':
      case 'unpin':
        try {
          await chatService.pinMessage(message.id, message.conversationId, action === 'pin');
          setMessages(prev => prev.map(m =>
            m.id === message.id ? { ...m, pinned: action === 'pin' } : m
          ));
          Alert.alert('Success', action === 'pin' ? 'Message pinned' : 'Message unpinned');
        } catch (error) {
          Alert.alert('Error', 'Failed to pin message');
        }
        break;

      case 'edit':
        setEditingMessage(message);
        setEditText(message.content);
        setShowMessageActions(false);
        break;

      case 'react':
        setShowEmojiPicker(true);
        break;

      case 'download':
        if (message.fileUrl) {
          Alert.alert('Download', 'File download feature will be available soon');
        }
        break;
    }

    setShowMessageActions(false);
    setSelectedMessageForAction(null);
  };

  const cancelReply = () => {
    setReplyingTo(null);
  };

  // Handle edit message
  const handleEditMessage = async () => {
    if (!editingMessage || !editText.trim()) return;

    try {
      const updated = await chatService.editMessage(editingMessage.id, editText.trim(), user?.id || '');

      setMessages(prev => prev.map(msg =>
        msg.id === editingMessage.id
          ? { ...msg, content: editText.trim(), isEdited: true }
          : msg
      ));

      setEditingMessage(null);
      setEditText('');
      Alert.alert('Success', 'Message updated');
    } catch (error) {
      console.error('Error editing message:', error);
      Alert.alert('Error', 'Failed to edit message');
    }
  };

  // Cancel edit
  const cancelEdit = () => {
    setEditingMessage(null);
    setEditText('');
  };

  // Handle reaction
  const handleReaction = async (emoji: string) => {
    if (!selectedMessageForAction || !user) return;

    try {
      const result = await chatService.reactToMessage(
        selectedMessageForAction.id,
        emoji,
        user.id,
        'Staff'
      );

      setMessages(prev => prev.map(msg =>
        msg.id === selectedMessageForAction.id
          ? { ...msg, reactions: result.reactions }
          : msg
      ));

      setShowEmojiPicker(false);
      setSelectedMessageForAction(null);
    } catch (error) {
      console.error('Error reacting to message:', error);
      Alert.alert('Error', 'Failed to add reaction');
    }
  };

  // Handle forward message
  const handleForward = async (contactId: string, contactUserType: 'staff' | 'student') => {
    if (!forwardingMessage || !user) return;

    try {
      // Get or create conversation
      const conversation = await chatService.createConversation(
        user.id,
        'staff',
        contactId,
        contactUserType
      );

      // Send forwarded message
      socketService.sendMessage({
        conversationId: conversation.id,
        receiverId: contactId,
        receiverModel: contactUserType === 'staff' ? 'Staff' : 'Student',
        content: forwardingMessage.content,
        type: forwardingMessage.type,
        fileUrl: forwardingMessage.fileUrl,
        fileName: forwardingMessage.fileName,
        fileSize: forwardingMessage.fileSize,
        forwardedFrom: {
          messageId: forwardingMessage.id,
          conversationId: forwardingMessage.conversationId,
          forwardedBy: user.id,
          originalSenderName: forwardingMessage.senderName,
        },
      });

      setShowForwardModal(false);
      setForwardingMessage(null);
      Alert.alert('Success', 'Message forwarded');
    } catch (error) {
      console.error('Error forwarding message:', error);
      Alert.alert('Error', 'Failed to forward message');
    }
  };

  // Handle back navigation
  const handleBack = () => {
    if (selectedConversation) {
      // Leave conversation room
      socketService.leaveConversation(selectedConversation.id);
      setSelectedConversation(null);
      setMessages([]);
      setTypingUsers(new Set());
    }
  };

  const filteredConversations = conversations.filter(c =>
    c.otherParticipant?.name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
    c.groupName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
    c.lastMessage?.content?.toLowerCase().includes(searchQuery.toLowerCase())
  );

  // Calculate total unread count
  const totalUnread = conversations.reduce((acc, c) => acc + (c.unreadCount || 0), 0);

  // Chat screen
  if (selectedConversation) {
    const displayName = selectedConversation.type === 'group'
      ? selectedConversation.groupName || 'Group'
      : selectedConversation.otherParticipant?.name || 'Unknown';

    const isOnline = selectedConversation.type === 'group'
      ? true
      : selectedConversation.otherParticipant?.online || false;

    return (
      <View style={[styles.container, { backgroundColor: colors.background }]}>
        <StatusBar barStyle={activeTheme === 'dark' ? 'light-content' : 'light-content'} backgroundColor={colors.primary} />

        {/* Header */}
        <View style={[styles.chatHeader, { backgroundColor: colors.primary }]}>
          <TouchableOpacity
            style={styles.backButton}
            onPress={handleBack}
          >
            <Ionicons name="arrow-back" size={24} color={colors.white} />
          </TouchableOpacity>
          <View style={styles.chatHeaderInfo}>
            <View style={styles.chatAvatar}>
              <Text style={[styles.chatAvatarText, { color: colors.white }]}>
                {displayName.charAt(0).toUpperCase()}
              </Text>
              {isOnline && <View style={[styles.onlineIndicatorSmall, { borderColor: colors.primary }]} />}
            </View>
            <View>
              <Text style={[styles.chatTitle, { color: colors.white }]} numberOfLines={1}>
                {displayName}
              </Text>
              <Text style={styles.chatSubtitle}>
                {isOnline ? 'Online' : 'Offline'}
              </Text>
            </View>
          </View>
          <TouchableOpacity style={styles.headerButton}>
            <Ionicons name="ellipsis-vertical" size={22} color={colors.white} />
          </TouchableOpacity>
        </View>

        {/* Messages List */}
        <ScrollView
          ref={scrollViewRef}
          style={styles.messagesContainer}
          contentContainerStyle={styles.messagesContent}
          onContentSizeChange={() => scrollViewRef.current?.scrollToEnd({ animated: true })}
          showsVerticalScrollIndicator={false}
          nestedScrollEnabled={true}
          scrollEventThrottle={16}
        >
          <View style={styles.dateSeparator}>
            <Text style={[styles.dateSeparatorText, { backgroundColor: colors.border, color: colors.textSecondary }]}>Today</Text>
          </View>
          {messages.map((message) => (
            <MessageBubble
              key={message.id}
              message={message}
              isOwn={String(message.senderId) === String(user?.id)}
              onLongPress={handleMessageLongPress}
              colors={colors}
            />
          ))}
          {typingUsers.size > 0 && <TypingIndicator colors={colors} />}
        </ScrollView>

        {/* Input Area */}
        <KeyboardAvoidingView
          behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
          keyboardVerticalOffset={Platform.OS === 'ios' ? 90 : 0}
        >
          <View style={[styles.inputWrapper, { backgroundColor: colors.card, borderTopColor: colors.border }]}>
            {/* Reply Indicator */}
            {replyingTo && (
              <View style={[styles.replyToContainer, { backgroundColor: colors.backgroundGray, borderBottomColor: colors.border }]}>
                <View style={styles.replyToContent}>
                  <View style={[styles.replyToBar, { backgroundColor: colors.primary }]} />
                  <View style={styles.replyToText}>
                    <Text style={[styles.replyToLabel, { color: colors.primary }]}>
                      Replying to {replyingTo.senderName}
                    </Text>
                    <Text style={[styles.replyToMessage, { color: colors.textSecondary }]} numberOfLines={1}>
                      {replyingTo.content || (replyingTo.type === 'image' ? '📷 Image' : '📎 File')}
                    </Text>
                  </View>
                </View>
                <TouchableOpacity onPress={cancelReply} style={styles.replyToCancel}>
                  <Ionicons name="close-circle" size={20} color={colors.textSecondary} />
                </TouchableOpacity>
              </View>
            )}

            {/* Edit Message Indicator */}
            {editingMessage && (
              <View style={[styles.editContainer, { backgroundColor: colors.primary + '10', borderBottomColor: colors.border }]}>
                <View style={styles.editContent}>
                  <View style={[styles.editBar, { backgroundColor: colors.primary }]} />
                  <View style={styles.editText}>
                    <Text style={[styles.editLabel, { color: colors.primary }]}>
                      Editing message
                    </Text>
                    <Text style={[styles.editMessage, { color: colors.textSecondary }]} numberOfLines={1}>
                      {editingMessage.content}
                    </Text>
                  </View>
                </View>
                <TouchableOpacity onPress={cancelEdit} style={styles.editCancel}>
                  <Ionicons name="close-circle" size={20} color={colors.textSecondary} />
                </TouchableOpacity>
              </View>
            )}

            {/* File Preview */}
            {selectedFile && (
              <View style={[styles.filePreviewContainer, { borderBottomColor: colors.border }]}>
                {selectedFile.type.startsWith('image/') ? (
                  <Image source={{ uri: selectedFile.uri }} style={styles.filePreviewImage} />
                ) : (
                  <View style={styles.filePreviewPlaceholder}>
                    <Ionicons name="document" size={32} color={colors.primary} />
                  </View>
                )}
                <View style={styles.filePreviewInfo}>
                  <Text style={[styles.filePreviewName, { color: colors.text }]} numberOfLines={1}>
                    {selectedFile.name}
                  </Text>
                  {selectedFile.size && (
                    <Text style={[styles.filePreviewSize, { color: colors.textSecondary }]}>
                      {(selectedFile.size / 1024).toFixed(2)} KB
                    </Text>
                  )}
                </View>
                {uploadingFile ? (
                  <View style={styles.uploadProgressContainer}>
                    <ActivityIndicator size="small" color={colors.primary} />
                    <Text style={[styles.uploadProgressText, { color: colors.primary }]}>{uploadProgress}%</Text>
                  </View>
                ) : (
                  <>
                    <TouchableOpacity
                      style={[styles.fileSendButton, { backgroundColor: colors.primary }]}
                      onPress={handleFileUpload}
                    >
                      <Ionicons name="send" size={20} color={colors.white} />
                    </TouchableOpacity>
                    <TouchableOpacity
                      style={[styles.fileCancelButton, { backgroundColor: colors.border }]}
                      onPress={cancelFileUpload}
                    >
                      <Ionicons name="close" size={20} color={colors.text} />
                    </TouchableOpacity>
                  </>
                )}
              </View>
            )}

            <View style={styles.inputContainer}>
              <TouchableOpacity
                style={styles.attachButton}
                onPress={() => setShowAttachmentModal(true)}
              >
                <Ionicons name="add-circle" size={28} color={colors.primary} />
              </TouchableOpacity>
              <View style={[styles.inputInner, { backgroundColor: colors.inputBackground, borderColor: colors.border }]}>
                <TextInput
                  ref={inputRef}
                  style={[styles.input, { color: colors.text }]}
                  value={editingMessage ? editText : newMessage}
                  onChangeText={editingMessage ? setEditText : handleTyping}
                  placeholder={editingMessage ? "Edit message..." : "Type a message..."}
                  placeholderTextColor={colors.textSecondary}
                  multiline
                  maxLength={1000}
                />
              </View>
              {editingMessage ? (
                <TouchableOpacity
                  style={[styles.sendButton, { backgroundColor: colors.success }, !editText.trim() && styles.sendButtonHidden]}
                  onPress={handleEditMessage}
                >
                  <Ionicons name="checkmark" size={22} color={colors.white} />
                </TouchableOpacity>
              ) : (
                <TouchableOpacity
                  style={[styles.sendButton, { backgroundColor: colors.primary }, !newMessage.trim() && styles.sendButtonHidden]}
                  onPress={sendMessage}
                  disabled={sending}
                >
                  {sending ? (
                    <ActivityIndicator size="small" color={colors.white} />
                  ) : (
                    <Ionicons name="send" size={20} color={colors.white} />
                  )}
                </TouchableOpacity>
              )}
            </View>
          </View>
        </KeyboardAvoidingView>

        {/* Attachment Options Modal */}
        <Modal
          visible={showAttachmentModal}
          transparent={true}
          animationType="slide"
          onRequestClose={() => setShowAttachmentModal(false)}
        >
          <TouchableOpacity
            style={styles.modalOverlay}
            activeOpacity={1}
            onPress={() => setShowAttachmentModal(false)}
          >
            <View style={[styles.attachmentModalContent, { backgroundColor: colors.card }]}>
              <View style={[styles.attachmentModalHeader, { borderBottomColor: colors.border }]}>
                <Text style={[styles.attachmentModalTitle, { color: colors.text }]}>Send Attachment</Text>
                <TouchableOpacity
                  style={[styles.attachmentCloseButton, { backgroundColor: colors.border }]}
                  onPress={() => setShowAttachmentModal(false)}
                >
                  <Ionicons name="close" size={24} color={colors.text} />
                </TouchableOpacity>
              </View>

              <View style={styles.attachmentOptionsContainer}>
                <TouchableOpacity
                  style={[styles.attachmentOption, { backgroundColor: colors.backgroundGray }]}
                  onPress={() => requestPermissionsAndPickImage(false)}
                >
                  <View style={[styles.attachmentOptionIcon, { backgroundColor: colors.primary + '15' }]}>
                    <Ionicons name="images" size={32} color={colors.primary} />
                  </View>
                  <Text style={[styles.attachmentOptionText, { color: colors.text }]}>Photo Library</Text>
                  <Text style={[styles.attachmentOptionSubtext, { color: colors.textSecondary }]}>Choose from gallery</Text>
                </TouchableOpacity>

                <TouchableOpacity
                  style={[styles.attachmentOption, { backgroundColor: colors.backgroundGray }]}
                  onPress={() => requestPermissionsAndPickImage(true)}
                >
                  <View style={[styles.attachmentOptionIcon, { backgroundColor: colors.primary + '15' }]}>
                    <Ionicons name="camera" size={32} color={colors.primary} />
                  </View>
                  <Text style={[styles.attachmentOptionText, { color: colors.text }]}>Camera</Text>
                  <Text style={[styles.attachmentOptionSubtext, { color: colors.textSecondary }]}>Take a photo</Text>
                </TouchableOpacity>
              </View>
            </View>
          </TouchableOpacity>
        </Modal>

        {/* Message Actions Modal */}
        <Modal
          visible={showMessageActions}
          transparent={true}
          animationType="fade"
          onRequestClose={() => setShowMessageActions(false)}
        >
          <TouchableOpacity
            style={styles.modalOverlay}
            activeOpacity={1}
            onPress={() => setShowMessageActions(false)}
          >
            <View style={styles.messageActionsContainer}>
              <View style={[styles.messageActionsContent, { backgroundColor: colors.card }]}>
                <View style={[styles.messageActionsHeader, { borderBottomColor: colors.border }]}>
                  <Text style={[styles.messageActionsTitle, { color: colors.text }]}>Message Actions</Text>
                  <TouchableOpacity
                    style={[styles.messageActionsCloseButton, { backgroundColor: colors.border }]}
                    onPress={() => setShowMessageActions(false)}
                  >
                    <Ionicons name="close" size={24} color={colors.text} />
                  </TouchableOpacity>
                </View>

                <View style={styles.messageActionsList}>
                  <TouchableOpacity
                    style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                    onPress={() => handleMessageAction('reply')}
                  >
                    <Ionicons name="arrow-undo" size={24} color={colors.primary} />
                    <Text style={[styles.messageActionText, { color: colors.text }]}>Reply</Text>
                  </TouchableOpacity>

                  <TouchableOpacity
                    style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                    onPress={() => handleMessageAction('forward')}
                  >
                    <Ionicons name="arrow-forward" size={24} color={colors.primary} />
                    <Text style={[styles.messageActionText, { color: colors.text }]}>Forward</Text>
                  </TouchableOpacity>

                  {String(selectedMessageForAction?.senderId) === String(user?.id) && (
                    <>
                      <TouchableOpacity
                        style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                        onPress={() => handleMessageAction('edit')}
                      >
                        <Ionicons name="create" size={24} color={colors.primary} />
                        <Text style={[styles.messageActionText, { color: colors.text }]}>Edit</Text>
                      </TouchableOpacity>

                      <TouchableOpacity
                        style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                        onPress={() => handleMessageAction('delete')}
                      >
                        <Ionicons name="trash" size={24} color={colors.error} />
                        <Text style={[styles.messageActionText, { color: colors.error }]}>Delete</Text>
                      </TouchableOpacity>
                    </>
                  )}

                  <TouchableOpacity
                    style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                    onPress={() => handleMessageAction('copy')}
                  >
                    <Ionicons name="copy" size={24} color={colors.primary} />
                    <Text style={[styles.messageActionText, { color: colors.text }]}>Copy Text</Text>
                  </TouchableOpacity>

                  <TouchableOpacity
                    style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                    onPress={() => handleMessageAction('react')}
                  >
                    <Ionicons name="happy-outline" size={24} color={colors.primary} />
                    <Text style={[styles.messageActionText, { color: colors.text }]}>React</Text>
                  </TouchableOpacity>

                  <TouchableOpacity
                    style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                    onPress={() => handleMessageAction(selectedMessageForAction?.pinned ? 'unpin' : 'pin')}
                  >
                    <Ionicons name={selectedMessageForAction?.pinned ? "pin" : "pin-outline"} size={24} color={colors.primary} />
                    <Text style={[styles.messageActionText, { color: colors.text }]}>
                      {selectedMessageForAction?.pinned ? 'Unpin' : 'Pin'}
                    </Text>
                  </TouchableOpacity>

                  {(selectedMessageForAction?.type === 'file' || selectedMessageForAction?.type === 'image') && (
                    <TouchableOpacity
                      style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                      onPress={() => handleMessageAction('download')}
                    >
                      <Ionicons name="download" size={24} color={colors.primary} />
                      <Text style={[styles.messageActionText, { color: colors.text }]}>Download</Text>
                    </TouchableOpacity>
                  )}
                </View>
              </View>
            </View>
          </TouchableOpacity>
        </Modal>

        {/* Emoji Picker Modal */}
        <Modal
          visible={showEmojiPicker}
          transparent={true}
          animationType="fade"
          onRequestClose={() => setShowEmojiPicker(false)}
        >
          <TouchableOpacity
            style={styles.modalOverlay}
            activeOpacity={1}
            onPress={() => {
              setShowEmojiPicker(false);
              setSelectedMessageForAction(null);
            }}
          >
            <View style={styles.emojiPickerContainer}>
              <View style={[styles.emojiPickerContent, { backgroundColor: colors.card }]}>
                <Text style={[styles.emojiPickerTitle, { color: colors.text }]}>Add Reaction</Text>
                <View style={styles.emojiGrid}>
                  {['👍', '❤️', '😂', '😮', '😢', '🎉', '👏', '🔥', '💯', '🙏', '😍', '🤔'].map((emoji) => (
                    <TouchableOpacity
                      key={emoji}
                      style={[styles.emojiButton, { backgroundColor: colors.backgroundGray }]}
                      onPress={() => handleReaction(emoji)}
                    >
                      <Text style={styles.emojiText}>{emoji}</Text>
                    </TouchableOpacity>
                  ))}
                </View>
              </View>
            </View>
          </TouchableOpacity>
        </Modal>

        {/* Forward Modal */}
        <Modal
          visible={showForwardModal}
          transparent={true}
          animationType="slide"
          onRequestClose={() => {
            setShowForwardModal(false);
            setForwardingMessage(null);
            setContactsSearchQuery('');
          }}
        >
          <View style={styles.modalOverlay}>
            <View style={[styles.modalContent, { backgroundColor: colors.card }]}>
              {/* Modal Header */}
              <View style={[styles.modalHeader, { borderBottomColor: colors.border }]}>
                <Text style={[styles.modalTitle, { color: colors.text }]}>Forward Message</Text>
                <TouchableOpacity
                  style={[styles.modalCloseButton, { backgroundColor: colors.border }]}
                  onPress={() => {
                    setShowForwardModal(false);
                    setForwardingMessage(null);
                    setContactsSearchQuery('');
                  }}
                >
                  <Ionicons name="close" size={24} color={colors.text} />
                </TouchableOpacity>
              </View>

              {/* Forward Preview */}
              {forwardingMessage && (
                <View style={[styles.forwardPreview, { backgroundColor: colors.backgroundGray }]}>
                  <Ionicons name="arrow-forward" size={16} color={colors.primary} />
                  <Text style={[styles.forwardPreviewText, { color: colors.textSecondary }]} numberOfLines={2}>
                    {forwardingMessage.content || (forwardingMessage.type === 'image' ? '📷 Image' : '📎 File')}
                  </Text>
                </View>
              )}

              {/* Search Bar */}
              <View style={[styles.modalSearchBar, { backgroundColor: colors.backgroundGray, borderColor: colors.border }]}>
                <Ionicons name="search" size={18} color={colors.textSecondary} />
                <TextInput
                  style={[styles.modalSearchInput, { color: colors.text }]}
                  value={contactsSearchQuery}
                  onChangeText={setContactsSearchQuery}
                  placeholder="Search contacts..."
                  placeholderTextColor={colors.textSecondary}
                />
                {contactsSearchQuery.length > 0 && (
                  <TouchableOpacity onPress={() => setContactsSearchQuery('')}>
                    <Ionicons name="close-circle" size={18} color={colors.textSecondary} />
                  </TouchableOpacity>
                )}
              </View>

              {/* Contacts List */}
              <ScrollView
                style={styles.modalContactsList}
                showsVerticalScrollIndicator={false}
              >
                {loadingContacts ? (
                  <View style={styles.modalLoadingContainer}>
                    <ActivityIndicator size="large" color={colors.primary} />
                  </View>
                ) : (
                  <>
                    {/* Staff Section */}
                    {availableContacts.staff.length > 0 && (
                      <View style={styles.contactSection}>
                        <Text style={[styles.contactSectionTitle, { color: colors.textSecondary }]}>Staff</Text>
                        {availableContacts.staff
                          .filter(s =>
                            s.name.toLowerCase().includes(contactsSearchQuery.toLowerCase()) ||
                            s.role?.toLowerCase().includes(contactsSearchQuery.toLowerCase())
                          )
                          .map(staff => (
                            <TouchableOpacity
                              key={staff.id}
                              style={[styles.contactItem, { backgroundColor: colors.card }]}
                              onPress={() => handleForward(staff.id, 'staff')}
                            >
                              <View style={[styles.contactAvatar, { backgroundColor: colors.primary + '15' }]}>
                                <Text style={[styles.contactAvatarText, { color: colors.primary }]}>
                                  {staff.name.charAt(0).toUpperCase()}
                                </Text>
                              </View>
                              <View style={styles.contactInfo}>
                                <Text style={[styles.contactName, { color: colors.text }]}>{staff.name}</Text>
                                {staff.role && (
                                  <Text style={[styles.contactRole, { color: colors.textSecondary }]}>{staff.role}</Text>
                                )}
                              </View>
                              <Ionicons name="arrow-forward" size={20} color={colors.primary} />
                            </TouchableOpacity>
                          ))}
                      </View>
                    )}

