      `${API_URL}/results`,
      {
        method: 'POST',
        headers: await this.getHeaders(),
        body: JSON.stringify({ examId, studentId, ...marks }),
      }
    );
    if (!response.ok) throw new Error('Failed to enter marks');
    return response.json();
  }

  async getPayslips(employeeId: string, year?: number, limit = 24, skip = 0) {
    const params = new URLSearchParams();
    if (year) params.append('year', year.toString());
    params.append('limit', limit.toString());
    params.append('skip', skip.toString());

    const response = await this.fetchWithTimeout(
      `${API_URL}/payslips/staff/${employeeId}?${params}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch payslips');
    return response.json();
  }

  async getPayslip(payslipId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/payslips/${payslipId}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch payslip');
    return response.json();
  }

  async getPayslipSummary(employeeId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/payslips/staff/${employeeId}/summary`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch payslip summary');
    return response.json();
  }

  async getStudentDetails(teacherId: string, studentId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/teacher/${teacherId}/student/${studentId}`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || errorData.message || 'Failed to fetch student details');
    }
    return response.json();
  }

  async downloadPayslip(payslipId: string) {
    const response = await this.fetchWithTimeout(
      `${API_URL}/payslips/${payslipId}/download`,
      {
        method: 'GET',
        headers: await this.getHeaders(),
      },
      30000 // 30 second timeout for PDF download
    );
    if (!response.ok) throw new Error('Failed to download payslip');
    return response.blob();
  }

  // Staff Profile Methods
  async getStaffProfile(staffId: string): Promise<StaffProfile> {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/staff/${staffId}/profile`,
      { headers: await this.getHeaders() }
    );
    if (!response.ok) throw new Error('Failed to fetch staff profile');
    return response.json();
  }

  async updateStaffProfile(staffId: string, data: ProfileUpdateRequest): Promise<StaffProfile> {
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/staff/${staffId}/profile`,
      {
        method: 'PUT',
        headers: await this.getHeaders(),
        body: JSON.stringify(data),
      }
    );
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || errorData.message || 'Failed to update staff profile');
    }
    return response.json();
  }

  async uploadProfilePhoto(staffId: string, uri: string): Promise<{ url: string }> {
    // Convert image URI to base64
    const base64Photo = await this.convertImageToBase64(uri);

    const token = await this.getToken();
    const response = await this.fetchWithTimeout(
      `${API_URL}/mobile/staff/${staffId}/photo`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...(token && { Authorization: `Bearer ${token}` }),
        },
        body: JSON.stringify({ photo: base64Photo }),
      },
      30000 // 30 second timeout for photo upload
    );
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || errorData.message || 'Failed to upload photo');
    }
    return response.json();
  }

  private async convertImageToBase64(uri: string): Promise<string> {
    try {
      // Fetch the image data
      const response = await fetch(uri);
      const blob = await response.blob();

      // Convert blob to base64
      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          // Get the base64 data and add data URI prefix
          const base64 = (reader.result as string);
          resolve(base64);
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });
    } catch (error) {
      throw new Error(`Failed to convert image to base64: ${error instanceof Error ? error.message : 'Unknown error'}`);
    }
  }
}

export default new APIService();

