import React, { useEffect, useState, useCallback } from 'react';
import {
    View,
    Text,
    ScrollView,
    StyleSheet,
    ActivityIndicator,
    Alert,
    Image,
    TouchableOpacity,
    Linking,
} from 'react-native';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { useLocalSearchParams } from 'expo-router';
import api from '../services/api';

export default function StudentDetailsScreen() {
    const { user } = useAuth();
    const { colors } = useTheme();
    const { id } = useLocalSearchParams();
    const [data, setData] = useState<any>(null);
    const [loading, setLoading] = useState(true);

    const loadStudentDetails = useCallback(async () => {
        if (!user?.id || !id) return;
        try {
            const response = await api.getStudentDetails(user.id, id as string);
            setData(response);
        } catch (error: any) {
            console.error('Error loading student details:', error);
            Alert.alert('Error', error.message || 'Failed to load student details');
        } finally {
            setLoading(false);
        }
    }, [user?.id, id]);

    useEffect(() => {
        loadStudentDetails();
    }, [loadStudentDetails]);

    if (loading) {
        return (
            <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', backgroundColor: colors.backgroundGray }}>
                <ActivityIndicator size="large" color={colors.primary} />
            </View>
        );
    }

    if (!data) return null;

    const { student, parents, attendance } = data;

    return (
        <ScrollView style={{ flex: 1, backgroundColor: colors.backgroundGray }}>
            {/* Header Profile */}
            <View style={{ padding: 24, backgroundColor: colors.primary, alignItems: 'center' }}>
                <View style={{ width: 80, height: 80, borderRadius: 40, backgroundColor: colors.white, justifyContent: 'center', alignItems: 'center', marginBottom: 12 }}>
                    <Text style={{ fontSize: 32, fontWeight: 'bold', color: colors.primary }}>{student.name.charAt(0)}</Text>
                </View>
                <Text style={{ fontSize: 24, fontWeight: 'bold', color: colors.white, marginBottom: 4 }}>{student.name}</Text>
                <Text style={{ fontSize: 14, color: colors.white + 'CC', marginBottom: 4 }}>Roll No: {student.rollNo} • Adm No: {student.admissionId}</Text>
                {student.class && (
                    <Text style={{ fontSize: 16, color: colors.white, fontWeight: '600', marginTop: 4, backgroundColor: 'rgba(255, 255, 255, 0.2)', paddingHorizontal: 12, paddingVertical: 4, borderRadius: 16 }}>
                        {student.class.name} {student.class.section}
                    </Text>
                )}
            </View>

            {/* Quick Actions */}
            <View style={{ flexDirection: 'row', padding: 16, gap: 12 }}>
                <TouchableOpacity
                    style={{ flex: 1, backgroundColor: colors.card, padding: 12, borderRadius: 12, alignItems: 'center', shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.05, shadowRadius: 2, elevation: 2 }}
                    onPress={() => parents[0]?.phone && Linking.openURL(`tel:${parents[0].phone}`)}
                >
                    <Text style={{ fontSize: 24, marginBottom: 4 }}>📞</Text>
                    <Text style={{ fontSize: 12, fontWeight: '600', color: colors.text }}>Call Parent</Text>
                </TouchableOpacity>
                <TouchableOpacity style={{ flex: 1, backgroundColor: colors.card, padding: 12, borderRadius: 12, alignItems: 'center', shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.05, shadowRadius: 2, elevation: 2 }}>
                    <Text style={{ fontSize: 24, marginBottom: 4 }}>💬</Text>
                    <Text style={{ fontSize: 12, fontWeight: '600', color: colors.text }}>Message</Text>
                </TouchableOpacity>
                <TouchableOpacity style={{ flex: 1, backgroundColor: colors.card, padding: 12, borderRadius: 12, alignItems: 'center', shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.05, shadowRadius: 2, elevation: 2 }}>
                    <Text style={{ fontSize: 24, marginBottom: 4 }}>📝</Text>
                    <Text style={{ fontSize: 12, fontWeight: '600', color: colors.text }}>Remark</Text>
                </TouchableOpacity>
            </View>

            {/* Attendance Stats */}
            <View style={{ margin: 16, marginTop: 0, padding: 16, backgroundColor: colors.card, borderRadius: 12, shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.05, shadowRadius: 2, elevation: 2 }}>
                <Text style={{ fontSize: 18, fontWeight: 'bold', color: colors.text, marginBottom: 16 }}>Attendance (Last 30 Days)</Text>
                <View style={{ flexDirection: 'row', justifyContent: 'space-around' }}>
                    <View style={{ alignItems: 'center' }}>
                        <Text style={{ fontSize: 24, fontWeight: 'bold', color: colors.success }}>{attendance.present}</Text>
                        <Text style={{ fontSize: 12, color: colors.textSecondary, marginTop: 4 }}>Present</Text>
                    </View>
                    <View style={{ alignItems: 'center' }}>
                        <Text style={{ fontSize: 24, fontWeight: 'bold', color: colors.error }}>{attendance.absent}</Text>
                        <Text style={{ fontSize: 12, color: colors.textSecondary, marginTop: 4 }}>Absent</Text>
                    </View>
                    <View style={{ alignItems: 'center' }}>
                        <Text style={{ fontSize: 24, fontWeight: 'bold', color: '#D97706' }}>{attendance.late}</Text>
                        <Text style={{ fontSize: 12, color: colors.textSecondary, marginTop: 4 }}>Late</Text>
                    </View>
                </View>
            </View>

            {/* Student Details */}
            <View style={{ margin: 16, marginTop: 0, padding: 16, backgroundColor: colors.card, borderRadius: 12, shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.05, shadowRadius: 2, elevation: 2 }}>
                <Text style={{ fontSize: 18, fontWeight: 'bold', color: colors.text, marginBottom: 16 }}>Personal Details</Text>
                <InfoRow label="Gender" value={student.gender} />
                <InfoRow label="Date of Birth" value={student.dob ? new Date(student.dob).toLocaleDateString() : '-'} />
                <InfoRow label="Address" value={student.address} />
                <InfoRow label="Student Phone" value={student.phone} />
            </View>

            {/* Parent Details */}
            <View style={{ margin: 16, marginTop: 0, padding: 16, backgroundColor: colors.card, borderRadius: 12, shadowColor: '#000', shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.05, shadowRadius: 2, elevation: 2 }}>
                <Text style={{ fontSize: 18, fontWeight: 'bold', color: colors.text, marginBottom: 16 }}>Parent Information</Text>
                {parents.map((parent: any, index: number) => (
                    <View key={index} style={{ marginBottom: 16, paddingBottom: 8, borderBottomWidth: 1, borderBottomColor: colors.backgroundGray }}>
                        <InfoRow label="Name" value={parent.name} />
                        <InfoRow label="Relationship" value={parent.relationship} />
                        <InfoRow label="Phone" value={parent.phone} />
                        <InfoRow label="Email" value={parent.email} />
                    </View>
                ))}
            </View>
        </ScrollView>
    );
}

function InfoRow({ label, value }: { label: string; value?: string }) {
    const { colors } = useTheme();
    if (!value) return null;
    return (
        <View style={{ flexDirection: 'row', justifyContent: 'space-between', paddingVertical: 8, borderBottomWidth: 1, borderBottomColor: colors.backgroundGray }}>
            <Text style={{ fontSize: 14, color: colors.textSecondary }}>{label}</Text>
            <Text style={{ fontSize: 14, color: colors.text, fontWeight: '500', flex: 1, textAlign: 'right', marginLeft: 16 }}>{value}</Text>
        </View>
    );
}

